_kcv_rows(txt) = [split(l) for l in split(txt, "\n")
                  if (f = split(l); length(f) >= 8 &&
                      (y = tryparse(Int, first(f)); y !== nothing && 1900 < y < 2100))]

@testset "keyword-isolation coverage vs live (NE/CS/LS)" begin
    keys = isdir(_KCV_DIR) ? sort(filter(f -> endswith(f, ".key"), readdir(_KCV_DIR))) : String[]
    @test !isempty(keys)   # fixtures must be present
    for kf in keys
        stem = kf[1:end-4]
        pfx = first(split(stem, "_"))
        V = get(_KCV_VARIANT, pfx, nothing)
        gold = joinpath(_KCV_DIR, "$stem.live.sum")
        if V === nothing || !isfile(gold); @test_skip "$stem: unknown variant prefix or missing golden"; continue; end
        @testset "$stem" begin
            jl = FVSjl.run_keyfile(joinpath(_KCV_DIR, kf); variant = V, output = :sum)  # variant= mandatory (see header)
            J = _kcv_rows(jl); L = _kcv_rows(read(gold, String))
            @test length(J) == length(L)
            if length(J) == length(L)
                # FULL-ROW bit-exact: every reported .sum column (TPA/BA/SDI/CCF/TopHt/QMD AND the
                # volume + mortality columns), so semantic divergences in vols/mort can't pass silently.
                cols(i) = 1:min(length(J[i]), length(L[i]))
                if haskey(_KCV_BROKEN, stem)
                    @test_broken all(J[i][c] == L[i][c] for i in 1:length(J), c in cols(i))
                else
                    for i in 1:length(J), c in cols(i)
                        @test J[i][c] == L[i][c]
                    end
                end
            end
        end
    end
end
